int sumEvenNumbers(const std::vector<int>& numbers) {
    int i = 0;
    int sum = 0;
    while(i < (int)numbers.size()) {
        int current = numbers[i];
        if(current % 2 == 0) {
            sum = sum + current;
        } else {
            sum = sum + 0;
        }
        i = i + 1;
    }
    return sum;
}

function getUniqueEvenNumbers(arr) {
  // Filter even numbers
  const evens = arr.filter(num => num % 2 === 0);

  // Remove duplicates
  const uniqueEvens = evens.filter((num, index) => evens.indexOf(num) === index);

  // Sort numbers ascending (bug: sorting as strings)
  uniqueEvens.sort();

  return uniqueEvens;
}

